const headers = $json.headers || {};
const role = String(headers["x-user-role"] || "").trim().toLowerCase();
const id = String(headers["x-user-id"] || role || "").trim();
const name = String(headers["x-user-name"] || role || "").trim();

if (!role) {
  return { json: { statusCode: 401, error: "expired", code: "session_missing" } };
}

return {
  json: {
    session: { id, name, role },
    params: $json.params || {},
    body: $json.body || {},
  },
};

const CONFIG = {
  AIRTABLE_PAT: $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY || "",
  AIRTABLE_BASE_ID: $env.AIRTABLE_BASE_ID || "",
  REVIEW_EPISODE_FIELD: $env.AIRTABLE_REVIEW_EPISODE_FIELD || "episode",
  REVIEW_AUTHOR_FIELD: $env.AIRTABLE_REVIEW_AUTHOR_FIELD || "author",
};

const request = this.helpers.httpRequest.bind(this.helpers);
const apiKey = String(CONFIG.AIRTABLE_PAT || "").trim();
const baseId = String(CONFIG.AIRTABLE_BASE_ID || "").trim();
const airtable = "https://api.airtable.com/v0/" + baseId;
const headers = { Authorization: "Bearer " + apiKey };
const episodeField = CONFIG.REVIEW_EPISODE_FIELD;
const authorField = CONFIG.REVIEW_AUTHOR_FIELD;
const REVIEW_FIELDS = [
  episodeField,
  authorField,
  "rating",
  "favorite_moment",
  "awkward_moment",
  "funny_quote",
  "summary",
  "would_redo",
  "song",
  "author_role",
];

if (!apiKey || !baseId) {
  return { json: { statusCode: 500, error: "Airtable config missing in n8n environment", code: "airtable_config_missing" } };
}

const escapeFormulaString = (value) => String(value || "").replace(/'/g, "\\'");
const fieldsQuery = (fields) => fields.map((field) => "fields%5B%5D=" + encodeURIComponent(field)).join("&");
const linkedIds = (value) => Array.isArray(value) ? value.map(String) : value ? [String(value)] : [];
const first = (value) => Array.isArray(value) ? value[0] : value;
const roleLabel = (role) => ({
  samuel: "Samuel",
  mathilde: "Mathilde",
  amis_samuel: "Amis de Samuel",
  amis_mathilde: "Amis de Mathilde",
}[role] || role || "");

async function findEpisodeRecord(id) {
  const cleanId = String(id || "").trim();
  if (!cleanId) return null;
  try {
    return await request({ method: "GET", url: airtable + "/Episodes/" + encodeURIComponent(cleanId), headers, json: true });
  } catch {}

  const formula = "OR(RECORD_ID() = '" + escapeFormulaString(cleanId) + "', {id} = '" + escapeFormulaString(cleanId) + "')";
  const data = await request({
    method: "GET",
    url: airtable + "/Episodes?maxRecords=1&filterByFormula=" + encodeURIComponent(formula),
    headers,
    json: true,
  });
  return data.records?.[0] || null;
}

async function findUserRecord(session) {
  const userId = String(session?.id || "").trim();
  const role = String(session?.role || "").trim().toLowerCase();
  if (userId) {
    try {
      return await request({ method: "GET", url: airtable + "/Users/" + encodeURIComponent(userId), headers, json: true });
    } catch {}
  }

  const formula = "OR(RECORD_ID() = '" + escapeFormulaString(userId) + "', {id} = '" + escapeFormulaString(userId) + "', LOWER({role}) = '" + escapeFormulaString(role) + "')";
  const data = await request({
    method: "GET",
    url: airtable + "/Users?maxRecords=1&filterByFormula=" + encodeURIComponent(formula),
    headers,
    json: true,
  });
  return data.records?.[0] || null;
}

async function listAllReviews() {
  const records = [];
  let offset = "";
  do {
    const url =
      airtable +
      "/Reviews?" +
      fieldsQuery(REVIEW_FIELDS) +
      "&pageSize=100" +
      (offset ? "&offset=" + encodeURIComponent(offset) : "");
    const data = await request({ method: "GET", url, headers, json: true });
    records.push(...(data.records || []));
    offset = data.offset || "";
  } while (offset);
  return records;
}

function reviewFromRecord(record, fallbackRole = "", fallbackName = "") {
  const f = record.fields || {};
  const role = String(first(f.author_role) || fallbackRole || "");
  return {
    id: record.id,
    author_role: role,
    author_name: String(first(f.author_name) || fallbackName || roleLabel(role)),
    rating: Number(f.rating || 0),
    favorite_moment: String(f.favorite_moment || ""),
    awkward_moment: String(f.awkward_moment || ""),
    funny_quote: String(f.funny_quote || ""),
    summary: String(f.summary || ""),
    would_redo: String(f.would_redo || ""),
    song: String(f.song || ""),
    updated_at: String(record.createdTime || ""),
  };
}
const session = $json.session;
const episode = await findEpisodeRecord($json.params?.id);
if (!episode) {
  return { json: { statusCode: 404, error: "Episode not found", code: "episode_missing" } };
}

let seasonUnlocked = false;
try {
  const settings = await request({
    method: "GET",
    url: airtable + "/Settings?maxRecords=1&fields%5B%5D=season_unlocked",
    headers,
    json: true,
  });
  seasonUnlocked = Boolean(settings.records?.[0]?.fields?.season_unlocked);
} catch {}

const CAN_SEE = {
  samuel: ["samuel"],
  mathilde: ["mathilde"],
  amis_samuel: ["amis_samuel", "amis_mathilde"],
  amis_mathilde: ["amis_samuel", "amis_mathilde"],
};
const allowedRoles = seasonUnlocked
  ? ["samuel", "mathilde", "amis_samuel", "amis_mathilde"]
  : CAN_SEE[session.role] || [];

const reviews = (await listAllReviews())
  .filter((record) => linkedIds(record.fields?.[episodeField]).includes(episode.id))
  .map((record) => reviewFromRecord(record))
  .filter((review) => allowedRoles.includes(review.author_role));

return { json: { reviews, season_unlocked: seasonUnlocked } };
